(()=>{const e=document.getElementById("root");if(e)e.outerHTML="<div id=\"front\" class=\"wrap\">\r\n  <div id=\"adminPreviewBar\" class=\"adminPreviewBar\"><div><strong>管理員預覽模式</strong><small id=\"previewAdminUser\"></small></div><div class=\"btns\"><button class=\"btn primary\" onclick=\"returnToAdmin()\">返回管理後台</button><button class=\"btn\" onclick=\"logout()\">登出</button></div></div>\r\n  <div class=\"top\">\r\n    <div class=\"brand\"><div id=\"secretLogo\" class=\"logo\" onclick=\"secretAdminTap()\" aria-label=\"公司Logo\"><img src=\"../assets/company-logo.png\" alt=\"公司Logo\"></div><div><h1>活動調查系統</h1><p>Enterprise Survey v7.0</p></div></div>\r\n    <div id=\"frontStatus\" class=\"pill\">載入中</div>\r\n  </div>\r\n  <div id=\"setup\" class=\"setup\">尚未填入 Firebase 設定。請在 HTML 裡找到 <b>firebaseConfig</b>，填入你的 Firebase Web App 設定。</div>\r\n  <div id=\"frontLoading\" class=\"card frontLoading\">正在讀取問卷設定...</div>\r\n  <div id=\"frontContent\" style=\"display:none\">\r\n    <section class=\"hero\"><h2 id=\"surveyTitle\"></h2><p id=\"surveyDesc\"></p><div id=\"deadline\" class=\"deadline\"></div></section>\r\n    <div id=\"finalFront\" class=\"final\" style=\"display:none\"></div>\r\n    <div id=\"closed\" class=\"closed\" style=\"display:none\">本次調查目前未開放或已截止，感謝大家。</div>\r\n    <div id=\"done\" class=\"card success\" style=\"display:none\"></div>\r\n    <div id=\"formGrid\" class=\"grid\">\r\n      <section class=\"card\"><h3>填寫問卷</h3>\r\n        <div class=\"field\"><label for=\"dept\">部門<span class=\"required\">*</span></label><select id=\"dept\" required><option value=\"\">請選擇部門</option></select></div>\r\n        <div class=\"field\"><label for=\"member\">姓名<span class=\"required\">*</span></label><select id=\"member\" required disabled><option value=\"\">請先選擇部門</option></select></div>\r\n        <div class=\"field attendanceModeField\"><label>參加狀態<span class=\"required\">*</span></label><div class=\"attendanceModeGroup\"><label class=\"attendanceModeChoice attend\"><input type=\"radio\" name=\"attendanceMode\" id=\"attendYes\" value=\"attend\"><span><b>可以參加</b><small>繼續選擇可配合的日期</small></span></label><label class=\"attendanceModeChoice cannot\"><input type=\"radio\" name=\"attendanceMode\" id=\"cannot\" value=\"cannot\"><span><b>不克參加</b><small>所有候選日期皆無法參加</small></span></label></div></div>\r\n        <div id=\"attendanceDateSection\" class=\"field\"><label>可參加日期（可複選）<span class=\"required\">*</span></label><div id=\"dateBox\" class=\"dateAvailabilityBox\"></div></div>\r\n        <div id=\"rankSection\" class=\"field\"><label>餐廳選擇順序</label><div id=\"rankGrid\" class=\"rankGrid\"></div></div>\r\n        <div class=\"field\"><label for=\"note\">備註（選填）</label><textarea id=\"note\" maxlength=\"500\"></textarea></div>\r\n        <div class=\"btns\"><button id=\"submitBtn\" class=\"btn primary\" onclick=\"submitVote()\">確認並送出</button><button class=\"btn\" onclick=\"resetVoteForm()\">清除內容</button></div><div id=\"submitStatus\" class=\"submitStatus\" role=\"status\" aria-live=\"polite\"></div>\r\n      </section>\r\n      <aside class=\"card\"><div id=\"frontInstructionsSection\" hidden><h3>填寫說明</h3><div id=\"editPolicyNotice\" class=\"notice\"></div><br></div><h3>餐廳資訊</h3><div id=\"restInfo\" class=\"restaurants\"></div></aside>\r\n    </div>\r\n  </div>\r\n</div>\r\n<div id=\"loginMask\" class=\"modalMask\"><div class=\"modal loginDialog\"><div class=\"modalHead loginBrand\"><img src=\"../assets/company-logo.png\" alt=\"環興科技股份有限公司\"></div><div class=\"loginActions\"><button id=\"loginBtn\" class=\"btn primary loginPrimary\" onclick=\"loginGoogle()\">使用 Google 登入</button><button class=\"loginCancel\" onclick=\"closeLogin()\">取消</button></div><p id=\"loginMsg\" class=\"loginMessage\" role=\"status\" aria-live=\"polite\"></p></div></div>\r\n<div id=\"responseEditMask\" class=\"modalMask responseEditMask\" role=\"dialog\" aria-modal=\"true\" aria-labelledby=\"responseEditTitle\"><div class=\"modal responseEditDialog\"><div class=\"responseEditHead\"><div><h2 id=\"responseEditTitle\">編輯同仁問卷</h2><p id=\"responseEditIdentity\"></p></div><button class=\"responseEditClose\" type=\"button\" onclick=\"closeResponseEditor()\" aria-label=\"關閉\">×</button></div><div class=\"responseEditBody\"><label class=\"responseCannotChoice\"><input id=\"responseEditCannot\" type=\"checkbox\" onchange=\"updateResponseEditorAvailability()\"><span><b>不克參加</b><small>勾選後會清除日期與餐廳選擇</small></span></label><div class=\"field\"><label>可參加日期（可複選）<span class=\"required\">*</span></label><div id=\"responseEditDates\" class=\"responseEditDates\"></div></div><div class=\"field\"><label>餐廳選擇順序</label><div id=\"responseEditRanks\" class=\"responseEditRanks\"></div></div><div class=\"field\"><label for=\"responseEditNote\">備註（選填）</label><textarea id=\"responseEditNote\" maxlength=\"500\"></textarea></div><div id=\"responseEditStatus\" class=\"submitStatus\" role=\"status\" aria-live=\"polite\"></div></div><div class=\"responseEditActions\"><button class=\"btn\" type=\"button\" onclick=\"closeResponseEditor()\">取消</button><button id=\"responseEditSaveBtn\" class=\"btn primary\" type=\"button\" onclick=\"saveResponseEdit()\">儲存修改</button></div></div></div>\r\n<div id=\"toast\" class=\"toast\"></div>\r\n<div id=\"admin\" class=\"admin\"><div class=\"layout\"><aside class=\"side\"><div class=\"ab\"><img src=\"../assets/company-logo.png\"><div><h2>活動調查後台</h2><small id=\"adminUser\"></small><small id=\"adminRole\" class=\"accessRole\"></small></div></div><button class=\"nav active\" data-access=\"all\" onclick=\"panel('dash',this)\">儀表板</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('surveyP',this)\">活動管理</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('memP',this)\">人員設定</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('dateP',this)\">日期管理</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('restP',this)\">餐廳管理</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('costP',this)\">費用試算</button><button class=\"nav\" data-access=\"all\" onclick=\"panel('respP',this)\">投票結果</button><button class=\"nav\" data-access=\"manager\" onclick=\"panel('finalP',this)\">最終決議</button><button class=\"nav\" data-access=\"system\" onclick=\"panel('sysMemP',this)\">人員管理</button><button class=\"nav\" data-access=\"system\" onclick=\"panel('accessP',this)\">權限管理</button><button class=\"nav\" data-access=\"all\" onclick=\"exportExcel()\">Excel 匯出</button><button class=\"nav\" data-access=\"all\" onclick=\"logout()\">登出</button></aside><main class=\"main\"><div class=\"head\"><h1 id=\"adminTitle\">儀表板</h1><div class=\"btns\" style=\"margin:0\"><select id=\"activeSurveySelect\" onchange=\"setActiveSurvey(this.value)\"></select><button class=\"btn\" onclick=\"copyAdminLink()\">複製本活動後台網址</button><button class=\"btn\" onclick=\"showFront()\">查看前台</button></div></div>\r\n<section id=\"dash\" class=\"panel active\"><div class=\"stats\"><div class=\"stat\"><b id=\"sFilled\">0</b><span>已填人數</span></div><div class=\"stat\"><b id=\"sTotal\">0</b><span>應填人數</span></div><div class=\"stat\"><b id=\"sRate\">0%</b><span>完成率</span><div class=\"progress\"><i id=\"bar\"></i></div></div><div class=\"stat\"><b id=\"sNo\">0</b><span>不克參加</span></div></div><div class=\"card\"><h3>目前活動</h3><div id=\"activeSurveyInfo\" class=\"notice\"></div><div class=\"btns\"><button class=\"btn primary\" onclick=\"panel('surveyP',document.querySelector('[onclick*=surveyP]'))\">建立或編輯活動</button><button class=\"btn green\" onclick=\"panel('respP',document.querySelector('[onclick*=respP]'))\">查看投票結果</button></div></div></section>\r\n<section id=\"surveyP\" class=\"panel\"><div class=\"card\"><div class=\"manageIntro\"><div><h3>活動管理</h3><p class=\"muted\">從活動列表選擇要編輯的項目，或建立一個全新活動。</p></div><button class=\"btn primary\" onclick=\"startNewSurvey()\">＋ 新增活動</button></div><div id=\"surveyEditor\" class=\"surveyEditor\"><div class=\"editorHead\"><div><h3 id=\"surveyFormHeading\">新增活動</h3><p id=\"surveyEditorContext\" class=\"editorContext\"></p></div><span id=\"surveyModeBadge\" class=\"modeBadge new\">新增模式</span></div><span id=\"surveyUnsaved\" class=\"unsavedMark\">● 尚未儲存的變更</span><div class=\"two\"><div class=\"field\"><label for=\"svTitle\">活動標題<span class=\"required\">*</span></label><input id=\"svTitle\" placeholder=\"115年第二次部門聚餐調查\"></div><div class=\"deadlineFields\"><div class=\"field\"><label for=\"svDeadline\">截止日期</label><input id=\"svDeadline\" type=\"date\"></div><div class=\"field\"><label for=\"svDeadlineTime\">截止時間</label><input id=\"svDeadlineTime\" type=\"time\" value=\"23:59\"></div></div></div><div class=\"field\"><label for=\"svDesc\">說明文字</label><textarea id=\"svDesc\" placeholder=\"感謝大家工作上的辛勞...\"></textarea></div><div class=\"field\"><label for=\"svInstructions\">前台填寫說明（選填）</label><textarea id=\"svInstructions\" maxlength=\"1000\" placeholder=\"例如：請勾選所有可以出席的日期；未勾選將視為無法出席。\"></textarea><small class=\"muted\">未填寫時，前台不會顯示「填寫說明」區塊。</small></div><div class=\"two\"><div class=\"field\"><label for=\"svStatus\">狀態</label><select id=\"svStatus\"><option value=\"open\">開放填寫</option><option value=\"closed\">已關閉</option><option value=\"draft\">草稿</option></select></div><div class=\"field\"><label for=\"svAllowEdit\">是否允許截止前修改</label><select id=\"svAllowEdit\"><option value=\"true\">允許</option><option value=\"false\">不允許</option></select></div></div><div class=\"field\"><label>參與部門</label><div id=\"targetDeptBox\" class=\"notice\"></div></div><div class=\"btns editorActions\"><button id=\"surveySaveBtn\" class=\"btn primary\" onclick=\"saveSurvey()\">建立活動</button><button class=\"btn\" onclick=\"cancelSurveyEdit()\">取消</button></div></div></div><div class=\"card\" style=\"margin-top:18px\"><div class=\"surveyListHead\"><h3>活動列表</h3><span class=\"muted\">「目前使用中」與編輯狀態分開管理</span></div><div id=\"surveyTable\"></div></div></section>\r\n<section id=\"memP\" class=\"panel\"><div class=\"card\"><div class=\"memberToolbar\"><div><h3>人員設定</h3><p class=\"muted\">設定本活動誰可以填寫問卷，以及哪些人納入預算計算。這裡只影響目前活動，不會修改系統人員主檔。</p></div></div><div class=\"budgetSettingBox\"><div><label for=\"budgetPerPerson\">每人預算</label><input id=\"budgetPerPerson\" type=\"number\" min=\"0\" step=\"1\" placeholder=\"例如：1200\"></div><button id=\"budgetSaveBtn\" class=\"btn primary\" onclick=\"saveBudgetSetting()\">儲存預算</button><small class=\"muted\">餐廳管理只維護單價；預算統一在此設定。</small></div><div id=\"memTable\"></div></div></section>\r\n<section id=\"sysMemP\" class=\"panel\"><div class=\"card\"><div class=\"memberToolbar\"><div><h3>人員管理</h3><p class=\"muted\">維護公司人員主檔及登入用 Google 帳號；活動管理者請到「人員設定」調整單一活動的填寫與預算資格。</p></div><div class=\"btns\"><button class=\"btn\" onclick=\"downloadMemberTemplate()\">下載標準範本</button><button class=\"btn\" onclick=\"chooseMemberImport()\">匯入 Excel</button><button class=\"btn green\" onclick=\"exportMembers()\">匯出名單</button><button class=\"btn primary\" onclick=\"startNewMember()\">＋ 新增人員</button><input id=\"memberImportInput\" class=\"fileInput\" type=\"file\" accept=\".xlsx,.xls,.csv\" onchange=\"importMembers(this.files[0]);this.value=''\" aria-label=\"匯入人員 Excel\"></div></div><div id=\"memberEditor\" class=\"memberEditor\"><div class=\"editorHead\"><h3 id=\"memberFormHeading\">新增人員</h3><span id=\"memberModeBadge\" class=\"modeBadge new\">新增模式</span></div><div class=\"memberFormGrid\"><div><label for=\"memDept\">部門<span class=\"required\">*</span></label><select id=\"memDept\"></select></div><div><label for=\"newMem\">姓名<span class=\"required\">*</span></label><input id=\"newMem\"></div><div><label for=\"newEmp\">員工編號<span class=\"required\">*</span></label><input id=\"newEmp\"></div><div><label for=\"memGoogle\">Google 帳號</label><input id=\"memGoogle\" type=\"email\" placeholder=\"name@gmail.com\"></div><div><label for=\"memStatus\">狀態</label><select id=\"memStatus\"><option value=\"true\">啟用</option><option value=\"false\">停用</option></select></div></div><div class=\"btns\"><button id=\"memberSaveBtn\" class=\"btn primary\" onclick=\"saveMember()\">新增人員</button><button class=\"btn\" onclick=\"cancelMemberEdit()\">取消</button></div></div><div id=\"memberImportResult\" class=\"memberImportResult\" role=\"status\" aria-live=\"polite\"></div><div id=\"sysMemberTable\"></div></div></section>\r\n<section id=\"dateP\" class=\"panel\"><div class=\"card\"><div class=\"editorHead\"><div><h3 id=\"dateFormHeading\">新增日期</h3><p class=\"muted\">新增可選日期，或從下方列表選擇既有日期進行修改。</p></div><span id=\"dateModeBadge\" class=\"modeBadge new\">新增模式</span></div><div class=\"inline3\"><div><label>日期顯示文字</label><input id=\"newDate\" placeholder=\"8/15（五）晚上\"></div><div><label>排序</label><input id=\"newDateSort\" type=\"number\"></div><div class=\"btns compactActions\"><button id=\"dateSaveBtn\" class=\"btn primary\" onclick=\"saveDateV731Direct()\">新增日期</button><button id=\"dateCancelBtn\" class=\"btn\" onclick=\"cancelDateEdit()\" hidden>取消編輯</button></div></div><div id=\"dateTable\"></div></div></section>\r\n<section id=\"restP\" class=\"panel\"><div class=\"card\"><div class=\"editorHead\"><div><h3 id=\"restFormHeading\">新增餐廳</h3><p class=\"muted\">新增餐廳，或從下方列表選擇既有餐廳進行修改。</p></div><span id=\"restModeBadge\" class=\"modeBadge new\">新增模式</span></div><div class=\"two\"><div class=\"field\"><label>餐廳名稱</label><input id=\"newRest\"></div><div class=\"field\"><label>排序</label><input id=\"newRestSort\" type=\"number\"></div></div><div class=\"two\"><div class=\"field\"><label>地址</label><input id=\"newAddr\"></div><div class=\"field\"><label>Google Map</label><input id=\"newMap\" placeholder=\"https://...\"></div></div><div class=\"field\"><label>餐廳單價</label><input id=\"newPrice\" type=\"number\" min=\"0\" step=\"1\" placeholder=\"例如：1188\"></div><div id=\"restVarianceHint\" class=\"restVarianceHint\" hidden>價差改由「人員設定」中的每人預算與餐廳單價試算。</div><div class=\"field\"><label>類型</label><textarea id=\"newCuisine\" placeholder=\"例如：鐵板燒、火鍋、排餐、合菜，可空白\"></textarea></div><div class=\"btns\"><button id=\"restSaveBtn\" class=\"btn primary\" onclick=\"saveRestaurant()\">新增餐廳</button><button id=\"restCancelBtn\" class=\"btn\" onclick=\"cancelRestaurantEdit()\" hidden>取消編輯</button></div><div id=\"restTable\"></div></div></section>\n<section id=\"respP\" class=\"panel\"><div class=\"card\"><h3>投票結果</h3><div id=\"resultTables\"></div></div></section>\r\n<section id=\"costP\" class=\"panel\"><div class=\"card\"><h3>費用試算</h3><p class=\"muted\">決議前可選擇任一票選日期與餐廳試算；此頁只做評估，不會寫入或覆蓋最終決議。</p><div class=\"two\"><div class=\"field\"><label>試算日期</label><select id=\"costDate\" onchange=\"renderCostEstimate()\"></select></div><div class=\"field\"><label>試算餐廳</label><select id=\"costRest\" onchange=\"renderCostEstimate()\"></select></div></div><div id=\"costEstimatePreview\"></div></div></section>\r\n<section id=\"finalP\" class=\"panel\"><div class=\"card\"><h3>結果鎖定 / 最終決議</h3><p class=\"muted\">選定最終日期後，系統會依同仁填寫的可參加日期自動整理出席名單。</p><div class=\"two\"><div class=\"field\"><label>最終日期</label><select id=\"finalDate\" onchange=\"renderFinalAttendancePreview()\"></select></div><div class=\"field\"><label>最終餐廳</label><select id=\"finalRest\" onchange=\"renderFinalAttendancePreview()\"></select></div></div><div class=\"field\"><label>決議說明</label><textarea id=\"finalNote\"></textarea></div><div class=\"field\"><label>前台顯示狀態</label><select id=\"finalLock\"><option value=\"false\">尚未決定</option><option value=\"true\">已決定並顯示於前台</option></select></div><div class=\"btns\"><button class=\"btn primary\" onclick=\"saveFinal()\">儲存最終決議</button><button class=\"btn green\" onclick=\"exportExcel()\">匯出 Excel</button></div><div id=\"finalAttendancePreview\"></div></div></section>\r\n<section id=\"accessP\" class=\"panel\"><div class=\"card\"><h3>活動權限管理</h3><p class=\"muted\">針對目前選取的活動指派負責人。管理者可編輯；檢視者僅能查看結果與匯出。</p><div class=\"accessForm\"><div><label for=\"managerEmail\">Google 帳號</label><input id=\"managerEmail\" type=\"email\" list=\"memberGoogleOptions\" placeholder=\"可輸入或選擇 Google 帳號\"><datalist id=\"memberGoogleOptions\"></datalist><small class=\"muted\">建議先在人員主檔維護 Google 帳號。</small></div><div><label for=\"managerRole\">權限</label><select id=\"managerRole\"><option value=\"manager\">活動管理者</option><option value=\"viewer\">結果檢視者</option></select></div><button class=\"btn primary\" onclick=\"saveSurveyManager()\">新增／更新權限</button></div><div id=\"managerTable\"></div></div></section>\r\n</main></div></div>";})();